# --- Caching Decorators ---

def require_cache(f):
    """Decorator that ensures cache is available before proceeding."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if cache is None:
            return jsonify({
                "error": "Cache service unavailable. Authentication not configured."
            }), 503
        return f(*args, **kwargs)
    return decorated_function


def cache_response(ttl=300, key_func=None):
    """
    Decorator to cache API responses.
    
    Args:
        ttl: Time to live in seconds
        key_func: Optional function to generate cache key from request
    """
    def decorator(f):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            if cache is None:
                return f(*args, **kwargs)

            # Generate cache key
            if key_func:
                cache_key = key_func()
            else:
                # Default: use endpoint + args + query string
                parts = [request.endpoint]
                if kwargs:
                    parts.append(json.dumps(kwargs, sort_keys=True))
                if request.args:
                    parts.append(json.dumps(dict(request.args), sort_keys=True))
                cache_key = "response:" + hashlib.md5(
                    ":".join(parts).encode('utf-8')
                ).hexdigest()

            # Try to get from cache
            cached = cache.get(cache_key)
            if cached is not None:
                response_data = cached
                response_data['_cache'] = 'HIT'
                return jsonify(response_data), 200

            # Execute the view function
            result = f(*args, **kwargs)

            # Handle tuple returns (response, status_code)
            if isinstance(result, tuple):
                response_data, status_code = result
            else:
                response_data = result
                status_code = 200

            # Only cache successful responses
            if status_code == 200 and isinstance(response_data, dict):
                cache.set(cache_key, response_data, ttl=ttl)
                response_data['_cache'] = 'MISS'
                return jsonify(response_data), status_code

            if isinstance(response_data, dict):
                return jsonify(response_data), status_code
            return result

        return decorated_function
    return decorator


def cache_query(key, ttl=300):
    """
    Cache a database query result.
    
    Args:
        key: Cache key for the query
        ttl: Time to live in seconds
    
    Returns:
        Cached result or None if not cached
    """
    if cache is None:
        return None
    return cache.get(key)


def store_query(key, data, ttl=300):
    """
    Store a database query result in cache.
    
    Args:
        key: Cache key
        data: Data to cache
        ttl: Time to live in seconds
    """
    if cache is None:
        return False
    return cache.set(key, data, ttl=ttl)


# --- Rate Limiting with Memcached ---

def rate_limit(max_requests=60, window=60):
    """
    Rate limiting decorator using Memcached.
    
    Args:
        max_requests: Maximum requests allowed in the window
        window: Time window in seconds
    """
    def decorator(f):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            if cache is None:
                return f(*args, **kwargs)

            # Use IP address as identifier
            client_ip = request.remote_addr or 'unknown'
            rate_key = f"ratelimit:{request.endpoint}:{client_ip}"

            current = cache.get(rate_key)
            if current is None:
                cache.set(rate_key, 1, ttl=window)
            elif current >= max_requests:
                return jsonify({
                    "error": "Rate limit exceeded",
                    "max_requests": max_requests,
                    "window_seconds": window,
                    "retry_after": window
                }), 429
            else:
                cache.incr(rate_key)

            return f(*args, **kwargs)
        return decorated_function
    return decorator


