# --- Batch Operations ---

@app.route('/users/batch', methods=['POST'])
@require_cache
@rate_limit(max_requests=30, window=60)
def get_users_batch():
    """Get multiple users by IDs with batch caching."""
    data = request.get_json()
    if not data or 'ids' not in data:
        return jsonify({"error": "Request body must contain 'ids' array"}), 400

    user_ids = data['ids']
    if not isinstance(user_ids, list) or len(user_ids) > 50:
        return jsonify({"error": "ids must be a list with max 50 items"}), 400

    # Try batch get from cache
    cache_keys = {f"user:{uid}": uid for uid in user_ids}
    cached_results = cache.get_multi(list(cache_keys.keys()))

    results = {}
    missing_ids = []

    for cache_key, uid in cache_keys.items():
        if cache_key in cached_results:
            results[uid] = cached_results[cache_key]
        else:
            missing_ids.append(uid)

    # Fetch missing from database
    new_cache_entries = {}
    for uid in missing_ids:
        user = db.get_user(uid)
        if user:
            results[uid] = user
            new_cache_entries[f"user:{uid}"] = user

    # Batch store in cache
    if new_cache_entries:
        cache.set_multi(new_cache_entries, ttl=180)

    return jsonify({
        "users": results,
        "cache_hits": len(user_ids) - len(missing_ids),
        "cache_misses": len(missing_ids),
        "total": len(results)
    })


